// Phase 4: Prepare Synthesis Input
// Kompiliert Sources und Claims in strukturierten Prompt-Kontext

const input = $input.first().json;
const sources = input.sources || [];
const claims = input.claims || [];
const searchPlan = input.search_plan || {};
const runId = input.run_id || 'unknown';
const mode = input.mode || 'standard';
const language = input.language || 'de';

// --- Sources nach Plattform gruppieren ---
const grouped = {};
for (const src of sources) {
  const platform = src.origin || src.source_type || 'unknown';
  if (!grouped[platform]) grouped[platform] = [];
  grouped[platform].push(src);
}

let contextParts = [];

// Header mit Metadaten
contextParts.push(`Run ID: ${runId}`);
contextParts.push(`Mode: ${mode}`);
contextParts.push(`Query: ${searchPlan.query || input.query || 'N/A'}`);
if (searchPlan.sub_questions && searchPlan.sub_questions.length > 0) {
  contextParts.push(`\nSub-Fragen:\n${searchPlan.sub_questions.map((q, i) => `  ${i + 1}. ${q}`).join('\n')}`);
}

// Sources nach Plattform
contextParts.push('\n--- QUELLEN ---');
for (const [platform, platformSources] of Object.entries(grouped)) {
  contextParts.push(`\n[${platform.toUpperCase()}] (${platformSources.length} Ergebnisse)`);
  for (const src of platformSources) {
    const tier = src.tier ? ` [${src.tier}]` : '';
    const score = src.relevance_score ? ` (relevance: ${src.relevance_score})` : '';
    contextParts.push(`  - ${src.title || 'Untitled'}${tier}${score}`);
    contextParts.push(`    URL: ${src.url || 'N/A'}`);
    if (src.snippet) {
      // Snippet kuerzen auf 500 Zeichen
      const snippet = src.snippet.length > 500 ? src.snippet.substring(0, 500) + '...' : src.snippet;
      contextParts.push(`    Inhalt: ${snippet}`);
    }
  }
}

// Claims mit Verifikationsstatus
if (claims.length > 0) {
  contextParts.push('\n--- CLAIMS ---');
  for (const claim of claims) {
    const status = claim.verification_status || claim.status || 'unverified';
    const confidence = claim.confidence ? ` (confidence: ${claim.confidence})` : '';
    contextParts.push(`  - [${status.toUpperCase()}]${confidence} ${claim.claim || claim.text || JSON.stringify(claim)}`);
    if (claim.counter_evidence) {
      contextParts.push(`    Gegenrecherche: ${claim.counter_evidence}`);
    }
    if (claim.supporting_sources && claim.supporting_sources.length > 0) {
      contextParts.push(`    Belegt durch: ${claim.supporting_sources.join(', ')}`);
    }
  }
}

// Gesamten Kontext zusammensetzen
let synthesisInput = contextParts.join('\n');

// Kontext-Limit: 80.000 Zeichen fuer CLI-Timeout-Schutz
const MAX_CONTEXT_LENGTH = 80000;
if (synthesisInput.length > MAX_CONTEXT_LENGTH) {
  synthesisInput = synthesisInput.substring(0, MAX_CONTEXT_LENGTH) + '\n\n[... Kontext gekuerzt wegen Laengenlimit ...]';
}

return [{
  json: {
    synthesis_input: synthesisInput,
    mode: mode,
    language: language,
    run_id: runId,
    source_count: sources.length,
    claim_count: claims.length,
    platform_count: Object.keys(grouped).length,
    platforms: Object.keys(grouped)
  }
}];

const { execSync } = require('child_process');

try {
  const result = execSync("={{ (() => {\n  const input = $json.synthesis_input.replace(/'/g, \"'\\\\''\")\n  const lang = $json.language || 'de';\n  return `gemini -p 'Erstelle einen Research-Report nach Template v3.\\n\\nTemplate v3 Struktur:\\n1. Executive Verdict (2-3 Saetze)\\n2. Entscheidungstabelle (wenn applicable)\\n3. Detailanalyse\\n4. Quellen-Uebersicht\\n5. Offene Risiken\\n6. Naechste Schritte\\n\\nSprache: ${lang}\\n\\nRecherche-Daten:\\n${input}' --sandbox`;\n})() }}", {
    encoding: 'utf-8',
    timeout: 120000,
    env: { ...process.env, PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin:' + process.env.PATH },
    cwd: '/home/clawd'
  });

  return [{ json: { stdout: result, exitCode: 0 } }];
} catch (error) {
  return [{ json: { stdout: error.stdout || '', stderr: error.stderr || error.message, exitCode: error.status || 1 } }];
}

const { execSync } = require('child_process');

try {
  const result = execSync("={{ (() => {\n  const input = $json.synthesis_input.replace(/'/g, \"'\\\\''\")\n  const lang = $json.language || 'de';\n  return `claude -p 'Erstelle einen umfassenden Research-Report nach Template v3.\\n\\nTemplate v3 Struktur:\\n1. Executive Verdict (2-3 Saetze, klare Empfehlung)\\n2. PRISMA Protocol (Suchstrategie, Ein-/Ausschlusskriterien)\\n3. Entscheidungstabelle\\n4. Detailanalyse (pro Sub-Frage)\\n5. Gegenrecherche & Widersprueche\\n6. Verification Table\\n7. Quellen-Uebersicht (mit Tier-Level)\\n8. Offene Risiken\\n9. Naechste Schritte\\n\\nSprache: ${lang}\\n\\nRecherche-Daten:\\n${input}' --model opus`;\n})() }}", {
    encoding: 'utf-8',
    timeout: 120000,
    env: { ...process.env, PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin:' + process.env.PATH },
    cwd: '/home/clawd'
  });

  return [{ json: { stdout: result, exitCode: 0 } }];
} catch (error) {
  return [{ json: { stdout: error.stdout || '', stderr: error.stderr || error.message, exitCode: error.status || 1 } }];
}

// Post-Process: Report extrahieren, Qualitaet bewerten

const cliOutput = $input.first().json;
const stdout = cliOutput.stdout || '';
const exitCode = cliOutput.exitCode;

// Metadaten vom vorherigen Code-Node ueber die Workflow-Daten holen
const prepNode = $('Prepare Synthesis Input').first().json;
const sourceCount = prepNode.source_count || 0;
const claimCount = prepNode.claim_count || 0;
const platformCount = prepNode.platform_count || 0;
const platforms = prepNode.platforms || [];
const mode = prepNode.mode || 'standard';
const runId = prepNode.run_id || 'unknown';

// --- Report Markdown extrahieren ---
let reportMarkdown = stdout.trim();

// Falls CLI Wrapper-Output hat, Markdown-Block extrahieren
const mdMatch = reportMarkdown.match(/```markdown\n?([\s\S]*?)\n?```/);
if (mdMatch) {
  reportMarkdown = mdMatch[1].trim();
}

// --- Titel generieren ---
let title = 'Research Report';
// Ersten H1 oder H2 Header als Titel verwenden
const titleMatch = reportMarkdown.match(/^#{1,2}\s+(.+)$/m);
if (titleMatch) {
  title = titleMatch[1].trim();
}

// --- Quality Score berechnen (0-100) ---
let qualityScore = 0;

// Faktor 1: Quellenanzahl (max 30 Punkte)
qualityScore += Math.min(sourceCount * 3, 30);

// Faktor 2: Claim-Anzahl (max 20 Punkte)
qualityScore += Math.min(claimCount * 4, 20);

// Faktor 3: Plattform-Diversitaet (max 25 Punkte)
qualityScore += Math.min(platformCount * 5, 25);

// Faktor 4: Report-Laenge als Proxy fuer Tiefe (max 15 Punkte)
const wordCount = reportMarkdown.split(/\s+/).length;
qualityScore += Math.min(Math.floor(wordCount / 100), 15);

// Faktor 5: CLI-Exit-Code (10 Punkte wenn erfolgreich)
if (exitCode === 0) {
  qualityScore += 10;
}

qualityScore = Math.min(qualityScore, 100);

// --- Confidence Score (0.0 - 1.0) ---
let confidenceScore = 0.0;

// Basis-Confidence aus Quellen
if (sourceCount >= 10) confidenceScore += 0.3;
else if (sourceCount >= 5) confidenceScore += 0.2;
else if (sourceCount >= 1) confidenceScore += 0.1;

// Plattform-Diversitaet
if (platformCount >= 4) confidenceScore += 0.25;
else if (platformCount >= 2) confidenceScore += 0.15;
else if (platformCount >= 1) confidenceScore += 0.05;

// Claims verifiziert
if (claimCount >= 5) confidenceScore += 0.25;
else if (claimCount >= 2) confidenceScore += 0.15;
else if (claimCount >= 1) confidenceScore += 0.1;

// Mode-Bonus
if (mode === 'deep') confidenceScore += 0.15;
else if (mode === 'standard') confidenceScore += 0.1;
else confidenceScore += 0.05;

confidenceScore = Math.min(confidenceScore, 1.0);
confidenceScore = parseFloat(confidenceScore.toFixed(2));

// --- Verdict extrahieren ---
let verdict = '';
// Versuche den Executive Verdict Abschnitt zu finden
const verdictMatch = reportMarkdown.match(/(?:Executive Verdict|Fazit|Verdict|Zusammenfassung)[:\s]*\n([\s\S]*?)(?:\n#{1,3}\s|\n---|\.\n\n)/i);
if (verdictMatch) {
  verdict = verdictMatch[1].trim().substring(0, 500);
} else {
  // Fallback: Erste 2 Saetze
  const sentences = reportMarkdown.replace(/^#.+\n/gm, '').trim().split(/\.\s+/);
  verdict = sentences.slice(0, 2).join('. ').trim();
  if (verdict && !verdict.endsWith('.')) verdict += '.';
}

// --- Template Compliance Check ---
const templateSections = mode === 'deep'
  ? ['Executive Verdict', 'PRISMA', 'Entscheidungstabelle', 'Detailanalyse', 'Gegenrecherche', 'Verification', 'Quellen', 'Risiken', 'Schritte']
  : ['Executive Verdict', 'Entscheidungstabelle', 'Detailanalyse', 'Quellen', 'Risiken', 'Schritte'];

const foundSections = templateSections.filter(section =>
  reportMarkdown.toLowerCase().includes(section.toLowerCase())
);
const templateCompliant = foundSections.length >= Math.ceil(templateSections.length * 0.6);

return [{
  json: {
    report_markdown: reportMarkdown,
    title: title,
    quality_score: qualityScore,
    confidence_score: confidenceScore,
    verdict: verdict,
    template_compliant: templateCompliant,
    run_id: runId,
    mode: mode,
    _meta: {
      source_count: sourceCount,
      claim_count: claimCount,
      platform_count: platformCount,
      platforms: platforms,
      word_count: wordCount,
      sections_found: foundSections,
      sections_expected: templateSections,
      cli_exit_code: exitCode
    }
  }
}];
